    with tempfile.TemporaryDirectory() as temp_dir:
        temp_path = Path(temp_dir)
        create_test_project_structure(temp_path)

        config = DocumentationConfig.from_project_root(temp_path)
        file_manager = FileManager(config)

        readme_path = temp_path / "README.md"
        original_content = readme_path.read_text()

        # Create backup
        backup_path = file_manager.create_backup(readme_path)

        assert backup_path.exists()
        assert backup_path.read_text() == original_content
        assert file_manager.backup_dir is not None
        assert len(file_manager.operations_log) == 2  # staging + backup

        # Test backup of non-existent file
        try:
            file_manager.create_backup(temp_path / "nonexistent.txt")
            assert False, "Should have raised FileManagerError"
        except FileManagerError:
            pass  # Expected

    print("✓ test_create_backup")


