def test_update_readme_section():
    """Test README section updating."""
    with tempfile.TemporaryDirectory() as temp_dir:
        temp_path = Path(temp_dir)
        create_test_project_structure(temp_path)

        config = DocumentationConfig.from_project_root(temp_path)
        file_manager = FileManager(config)

        new_tools_content = "New tools content here"

        # Update tools section
        result = file_manager.update_readme_section('tools', new_tools_content)

        assert result == True
        assert len(file_manager.staging_files) == 1

        # Check staging file content
        readme_path = temp_path / "README.md"
        staging_content = file_manager.get_staging_preview(readme_path)

        assert staging_content is not None
        assert new_tools_content in staging_content
        assert "Old tools content here" not in staging_content
        assert "<!--- Tools generated by update-docs.py --->" in staging_content
        assert "<!--- End of tools generated section --->" in staging_content

        # Test unknown section
        try:
            file_manager.update_readme_section('unknown', 'content')
            assert False, "Should have raised FileManagerError"
        except FileManagerError:
            pass  # Expected

    print("✓ test_update_readme_section")


def test_replace_section_content():
    """Test section content replacement logic."""
    with tempfile.TemporaryDirectory() as temp_dir:
        temp_path = Path(temp_dir)
        create_test_project_structure(temp_path)

        config = DocumentationConfig.from_project_root(temp_path)
        file_manager = FileManager(config)

        content = """Before
<!-- START TEST -->
Old content
<!-- END TEST -->
After"""

        new_content = "New content"

        result = file_manager._replace_section_content(
            content, "<!-- START TEST -->", "<!-- END TEST -->", new_content
        )

        assert "New content" in result
        assert "Old content" not in result
        assert "Before" in result
        assert "After" in result
        assert "<!-- START TEST -->" in result
        assert "<!-- END TEST -->" in result

        # Test missing markers
        try:
            file_manager._replace_section_content(
                content, "<!-- MISSING -->", "<!-- END TEST -->", new_content
            )
            assert False, "Should have raised FileManagerError"
        except FileManagerError:
            pass  # Expected

    print("✓ test_replace_section_content")


def test_validate_staging_files():
    """Test staging file validation."""
    with tempfile.TemporaryDirectory() as temp_dir:
        temp_path = Path(temp_dir)
        create_test_project_structure(temp_path)

        config = DocumentationConfig.from_project_root(temp_path)
        file_manager = FileManager(config)

        # Create valid staging file
        readme_path = temp_path / "README.md"
        file_manager.update_readme_section('tools', 'New tools content')

        # Validation should pass
        errors = file_manager.validate_staging_files()
        assert len(errors) == 0

        # Create invalid staging file (empty)
        staging_path = list(file_manager.staging_files.values())[0]
        staging_path.write_text("")

        errors = file_manager.validate_staging_files()
        assert len(errors) > 0
