def test_section_manager_validate_markers():
    """Test SectionManager marker validation."""
    with tempfile.TemporaryDirectory() as temp_dir:
        temp_path = Path(temp_dir)
        create_test_project_structure(temp_path)

        config = DocumentationConfig.from_project_root(temp_path)
        section_manager = SectionManager(config)

        # Valid content
        valid_content = create_test_readme_content()
        results = section_manager.validate_section_markers(valid_content)

        assert 'tools' in results
        assert 'resources' in results
        assert len(results['tools']) == 0  # No errors
